import anthropic, dataclasses, json
from typing import Any

@dataclasses.dataclass
class Step:
    step_index: int
    type: str                  # "llm_call" | "tool_call" | "tool_result"
    name: str | None           # tool name for tool_call/tool_result
    content: Any               # model response text or tool args or tool result
    stop_reason: str | None = None

@dataclasses.dataclass
class Trajectory:
    task_id: str
    task_input: str
    steps: list[Step]
    final_answer: str
    succeeded: bool

def run_and_record(task_id: str, task_input: str) -> Trajectory:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": task_input}]
    steps: list[Step] = []
    step_idx = 0

    tools = [
        {
            "name": "search",
            "description": "Search for factual information.",
            "input_schema": {
                "type": "object",
                "properties": {"query": {"type": "string"}},
                "required": ["query"],
            },
        },
        {
            "name": "calculator",
            "description": "Evaluate a numeric expression.",
            "input_schema": {
                "type": "object",
                "properties": {"expression": {"type": "string"}},
                "required": ["expression"],
            },
        },
    ]

    def fake_search(query: str) -> str:
        return f"[Search result for '{query}']: Sample result text."

    def fake_calc(expression: str) -> str:
        try:
            return str(eval(expression, {"__builtins__": {}}))
        except Exception as e:
            return f"Error: {e}"

    final_answer = ""
    for _ in range(10):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=tools,
            messages=messages,
        )
        response_text = " ".join(b.text for b in resp.content if hasattr(b, "text"))
        steps.append(Step(
            step_index=step_idx,
            type="llm_call",
            name=None,
            content={"text": response_text, "stop_reason": resp.stop_reason},
            stop_reason=resp.stop_reason,
        ))
        step_idx += 1

        if resp.stop_reason == "end_turn":
            final_answer = response_text
            break

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    steps.append(Step(
                        step_index=step_idx,
                        type="tool_call",
                        name=block.name,
                        content=block.input,
                    ))
                    step_idx += 1

                    result = (
                        fake_search(block.input["query"])
                        if block.name == "search"
                        else fake_calc(block.input.get("expression", "0"))
                    )
                    steps.append(Step(
                        step_index=step_idx,
                        type="tool_result",
                        name=block.name,
                        content=result,
                    ))
                    step_idx += 1
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })

            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    return Trajectory(
        task_id=task_id,
        task_input=task_input,
        steps=steps,
        final_answer=final_answer,
        succeeded=bool(final_answer),
    )

traj = run_and_record("task-001", "What is 17 * 24, and what is the capital of Japan?")
print(f"Steps: {len(traj.steps)}")
for s in traj.steps:
    label = s.name or "model"
    print(f"  [{s.step_index}] {s.type:12s} {label:12s} | {str(s.content)[:60]}")

def step_efficiency(actual_steps: int, min_steps: int) -> float:
    """
    Returns a score in (0, 1] where 1.0 = optimal.
    actual_steps: number of (LLM call + tool call) steps the agent took.
    min_steps: theoretical minimum for this task.
    """
    if actual_steps <= 0:
        return 0.0
    return min(1.0, min_steps / actual_steps)

# Counting steps from a trajectory
def count_action_steps(trajectory_steps: list[dict]) -> int:
    """Count LLM calls + tool calls (not tool results, which are passive)."""
    return sum(1 for s in trajectory_steps if s["type"] in ("llm_call", "tool_call"))

# Reference step counts for known task types
REFERENCE_STEPS = {
    "single_fact_lookup":      3,   # 1 llm + 1 search + 1 llm
    "two_fact_lookup":         5,   # 1 llm + 2 search + 2 llm (or 1 llm + 2 par + 1 llm)
    "math_with_search":        5,   # 1 llm + 1 search + 1 llm + 1 calc + 1 llm
    "direct_answer":           1,   # 1 llm, no tools needed
}

def score_trajectory(trajectory_steps: list[dict], task_type: str) -> dict:
    actual = count_action_steps(trajectory_steps)
    min_steps = REFERENCE_STEPS.get(task_type)
    if min_steps is None:
        return {"actual_steps": actual, "efficiency": None, "note": "no reference for task type"}
    efficiency = step_efficiency(actual, min_steps)
    return {
        "actual_steps": actual,
        "min_steps": min_steps,
        "efficiency": round(efficiency, 3),
        "grade": "optimal" if efficiency == 1.0 else "good" if efficiency >= 0.7 else "inefficient",
    }

sample_steps = [
    {"type": "llm_call"},
    {"type": "tool_call"},   # search
    {"type": "tool_result"},
    {"type": "llm_call"},
    {"type": "tool_call"},   # redundant second search
    {"type": "tool_result"},
    {"type": "llm_call"},
]
print(score_trajectory(sample_steps, "single_fact_lookup"))
# Output: {'actual_steps': 4, 'min_steps': 3, 'efficiency': 0.75, 'grade': 'good'}

import anthropic, json

def judge_step(
    task: str,
    step_text: str,
    tool_called: str | None,
    tool_args: dict | None,
    available_tools: list[str],
) -> dict:
    """
    Ask a judge model to evaluate one step of the agent's trajectory.
    Returns: {sound: bool, score: int (1-5), reasoning: str}
    """
    client = anthropic.Anthropic()

    tool_info = (
        f"The model called tool '{tool_called}' with args {json.dumps(tool_args)}."
        if tool_called else "The model did not call a tool."
    )

    prompt = f"""
You are evaluating one step of an AI agent solving the task: "{task}"

The agent said:
{step_text}

{tool_info}
Available tools: {', '.join(available_tools)}

Score the reasoning quality (1 = completely wrong/irrelevant, 5 = perfect):
- Was the reasoning logically sound?
- Was the tool choice (or lack of one) appropriate?
- Were the tool arguments well-formed for the task?

Reply with a JSON object: {{"score": <1-5>, "sound": <true|false>, "reasoning": "<one sentence>"}}
"""

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        raw = resp.content[0].text.strip()
        # Strip markdown code fences if present
        if raw.startswith("```"):
            raw = raw.split("```")[1]
            if raw.startswith("json"):
                raw = raw[4:]
        return json.loads(raw)
    except json.JSONDecodeError:
        return {"score": 3, "sound": True, "reasoning": "Could not parse judge response."}

verdict = judge_step(
    task="What is the population of Tokyo?",
    step_text="I need to search for the current population of Tokyo.",
    tool_called="search",
    tool_args={"query": "Tokyo population 2024"},
    available_tools=["search", "calculator"],
)
print(json.dumps(verdict, indent=2))
